const body = "<!-- ============== HERO ============== -->\n<section class=\"page-hero\">\n  <div class=\"glow\" aria-hidden=\"true\"></div>\n  <div class=\"container reveal\">\n    <a href=\"/portfolio\" class=\"btn btn-ghost\" style=\"padding:0;color:var(--mist-60);\">← Back to portfolio</a>\n    <div style=\"display:flex;gap:.6rem;flex-wrap:wrap;margin-top:1.25rem;\">\n      <span class=\"badge\"><span class=\"uae-flag-bar\"><span class=\"red\"></span><span class=\"green\"></span><span class=\"white\"></span><span class=\"black\"></span></span>Built for the UAE</span>\n      <span class=\"badge badge-success\">● Live in production</span>\n      <span class=\"badge\">Enterprise · 1,400 reqs/mo</span>\n      <span class=\"badge\">SLA 24h · audit-grade</span>\n    </div>\n    <h1 style=\"margin-top:1.25rem;max-width:22ch;\">Nine steps. One engine. Every approval, on the record.</h1>\n    <p class=\"lead\" style=\"max-width:64ch;\">A rules-based approval-routing platform for a UAE enterprise procurement team — replacing a fragile email-and-PDF process with a configurable routing graph, parallel-and-serial reviewers, escalation timers, and a tamper-evident audit ledger.</p>\n\n    <div style=\"display:flex;gap:1rem;margin-top:1.5rem;flex-wrap:wrap;\">\n      <a href=\"/contact\" class=\"btn btn-primary\">Book a workflow walkthrough\n        <svg class=\"arrow\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n      </a>\n      <a href=\"#flow\" class=\"btn btn-outline\">See the engine ↓</a>\n    </div>\n\n    <div class=\"launch-stats\">\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"1400\" data-suffix=\"\">0</span></div><div class=\"l\">requests · monthly</div></div>\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"71\" data-suffix=\"%\">0%</span></div><div class=\"l\">cycle-time reduction</div></div>\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"100\" data-suffix=\"%\">0%</span></div><div class=\"l\">audit coverage</div></div>\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"3.2\" data-suffix=\" reviewers\">0 reviewers</span></div><div class=\"l\">avg path length</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== WORKFLOW CANVAS ============== -->\n<section class=\"section\" id=\"flow\" style=\"padding-top:0;\">\n  <div class=\"container reveal\">\n    <div class=\"section-head\" style=\"margin-bottom:2rem;\">\n      <span class=\"eyebrow\">The engine</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Routing, escalation, sign-off — visible end-to-end.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">A live view of one in-flight purchase request, the rules that routed it, the reviewers it touched, and the moment it was signed. Everything is on the record.</p>\n    </div>\n\n    <div class=\"canvas\">\n\n      <div class=\"cv-chrome\">\n        <div class=\"dots\"><i></i><i></i><i></i></div>\n        <div class=\"url\"><span class=\"lock\">●</span> approvals.acmegroup.ae <span style=\"color:rgba(255,255,255,0.3);margin-left:auto;\">/ request · 4892</span></div>\n        <div class=\"actions\"><span>⌘K</span><span>?</span></div>\n      </div>\n\n      <div class=\"cv-top\">\n        <div>\n          <h3>Request #4892 · IT Hardware refresh · AED 280,000</h3>\n          <div class=\"meta\">Initiator · Hessa A. · IT &amp; Operations · raised 06-May-2026 09:14</div>\n        </div>\n        <div class=\"right\">\n          <span class=\"pill-mini live\"><i></i>IN FLIGHT</span>\n          <span class=\"pill-mini\">SLA · 18h remaining</span>\n          <span class=\"pill-mini\">Capex template</span>\n        </div>\n      </div>\n\n      <div class=\"cv-flow\">\n        <svg viewBox=\"0 0 1100 380\" xmlns=\"http://www.w3.org/2000/svg\">\n          <defs>\n            <marker id=\"pr-arr\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"7\" markerHeight=\"7\" orient=\"auto-start-reverse\"><path d=\"M0 0 L10 5 L0 10 z\" fill=\"rgba(122,240,184,0.55)\"/></marker>\n            <marker id=\"pr-arr-d\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"6\" markerHeight=\"6\" orient=\"auto-start-reverse\"><path d=\"M0 0 L10 5 L0 10 z\" fill=\"rgba(245,197,107,0.6)\"/></marker>\n            <linearGradient id=\"pr-g\" x1=\"0\" x2=\"1\" y1=\"0\" y2=\"0\"><stop offset=\"0\" stop-color=\"#19C37D\"/><stop offset=\"1\" stop-color=\"#7AF0B8\"/></linearGradient>\n            <linearGradient id=\"pr-amber\" x1=\"0\" x2=\"1\" y1=\"0\" y2=\"0\"><stop offset=\"0\" stop-color=\"#F5C56B\"/><stop offset=\"1\" stop-color=\"#FF8A3D\"/></linearGradient>\n          </defs>\n\n          <g font-family=\"'JetBrains Mono'\" font-size=\"9\" fill=\"rgba(255,255,255,0.4)\" text-anchor=\"middle\">\n            <text x=\"120\" y=\"22\">REQUEST</text>\n            <text x=\"380\" y=\"22\">RULE ENGINE</text>\n            <text x=\"700\" y=\"22\">REVIEWERS · PARALLEL</text>\n            <text x=\"980\" y=\"22\">SIGN-OFF</text>\n          </g>\n\n          <!-- 01 Request box -->\n          <g>\n            <rect x=\"20\" y=\"140\" width=\"200\" height=\"100\" rx=\"12\" fill=\"rgba(91,141,239,0.06)\" stroke=\"rgba(91,141,239,0.4)\"/>\n            <text x=\"120\" y=\"170\" text-anchor=\"middle\" fill=\"#9EBAF6\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"14\">PR-4892</text>\n            <text x=\"120\" y=\"192\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.7)\" font-family=\"'JetBrains Mono'\" font-size=\"10\">AED 280,000</text>\n            <text x=\"120\" y=\"210\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.5)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">capex · 32 SKUs</text>\n            <text x=\"120\" y=\"226\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.45)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">vendor: Tier-1 ITS</text>\n          </g>\n\n          <!-- 02 Decision diamond (rule engine) -->\n          <g>\n            <polygon points=\"380,80 480,180 380,280 280,180\" fill=\"rgba(25,195,125,0.06)\" stroke=\"rgba(25,195,125,0.5)\" stroke-width=\"1.5\"/>\n            <text x=\"380\" y=\"160\" text-anchor=\"middle\" fill=\"#7AF0B8\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"13\">Threshold</text>\n            <text x=\"380\" y=\"180\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"10\">amount &gt; 250K?</text>\n            <text x=\"380\" y=\"202\" text-anchor=\"middle\" fill=\"#7AF0B8\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"11\">YES → CFO + Legal</text>\n            <text x=\"220\" y=\"178\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.4)\" font-family=\"'JetBrains Mono'\" font-size=\"8\">280K</text>\n          </g>\n\n          <!-- 03 Reviewer A (Dept Head) -->\n          <g>\n            <rect x=\"540\" y=\"40\" width=\"200\" height=\"80\" rx=\"11\" fill=\"rgba(25,195,125,0.08)\" stroke=\"rgba(25,195,125,0.4)\"/>\n            <circle cx=\"565\" cy=\"65\" r=\"14\" fill=\"url(#pr-g)\"/>\n            <text x=\"565\" y=\"69\" text-anchor=\"middle\" fill=\"#072617\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"11\">FA</text>\n            <text x=\"588\" y=\"62\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"11\">Faisal A. · Dept head</text>\n            <text x=\"588\" y=\"78\" fill=\"rgba(255,255,255,0.55)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">approved · 09:42</text>\n            <text x=\"555\" y=\"105\" fill=\"rgba(122,240,184,0.85)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">✓ 28 min</text>\n          </g>\n\n          <!-- 04 Reviewer B (CFO - parallel) -->\n          <g>\n            <rect x=\"540\" y=\"140\" width=\"200\" height=\"80\" rx=\"11\" fill=\"rgba(25,195,125,0.08)\" stroke=\"rgba(25,195,125,0.4)\"/>\n            <circle cx=\"565\" cy=\"165\" r=\"14\" fill=\"url(#pr-g)\"/>\n            <text x=\"565\" y=\"169\" text-anchor=\"middle\" fill=\"#072617\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"11\">RM</text>\n            <text x=\"588\" y=\"162\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"11\">Reem M. · CFO</text>\n            <text x=\"588\" y=\"178\" fill=\"rgba(255,255,255,0.55)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">approved · 11:14</text>\n            <text x=\"555\" y=\"205\" fill=\"rgba(122,240,184,0.85)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">✓ 1h 32m</text>\n          </g>\n\n          <!-- 05 Reviewer C (Legal - parallel) -->\n          <g>\n            <rect x=\"540\" y=\"240\" width=\"200\" height=\"80\" rx=\"11\" fill=\"rgba(245,197,107,0.08)\" stroke=\"rgba(245,197,107,0.4)\"/>\n            <circle cx=\"565\" cy=\"265\" r=\"14\" fill=\"url(#pr-amber)\"/>\n            <text x=\"565\" y=\"269\" text-anchor=\"middle\" fill=\"#321a05\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"11\">JM</text>\n            <text x=\"588\" y=\"262\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"11\">Jasem M. · Legal</text>\n            <text x=\"588\" y=\"278\" fill=\"rgba(245,197,107,0.85)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">in review · 18h SLA</text>\n            <rect x=\"585\" y=\"295\" width=\"120\" height=\"6\" rx=\"3\" fill=\"rgba(255,255,255,0.06)\"/>\n            <rect x=\"585\" y=\"295\" width=\"48\" height=\"6\" rx=\"3\" fill=\"url(#pr-amber)\"/>\n            <text x=\"710\" y=\"301\" text-anchor=\"end\" fill=\"rgba(245,197,107,0.85)\" font-family=\"'JetBrains Mono'\" font-size=\"8\">38%</text>\n          </g>\n\n          <!-- 06 Final sign-off box -->\n          <g>\n            <rect x=\"900\" y=\"140\" width=\"180\" height=\"100\" rx=\"12\" fill=\"rgba(122,240,184,0.04)\" stroke=\"rgba(122,240,184,0.25)\" stroke-dasharray=\"5 4\"/>\n            <text x=\"990\" y=\"170\" text-anchor=\"middle\" fill=\"rgba(122,240,184,0.65)\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"14\">Sign-off</text>\n            <text x=\"990\" y=\"192\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.55)\" font-family=\"'JetBrains Mono'\" font-size=\"10\">awaiting all 3</text>\n            <text x=\"990\" y=\"210\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.4)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">PDF + audit hash</text>\n            <text x=\"990\" y=\"226\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.4)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">→ ERP + vendor</text>\n          </g>\n\n          <!-- arrows: PR → diamond -->\n          <g stroke=\"url(#pr-g)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#pr-arr)\">\n            <path d=\"M220 190 L 280 180\"/>\n          </g>\n\n          <!-- arrows: diamond → 3 reviewers (parallel) -->\n          <g stroke=\"url(#pr-g)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#pr-arr)\">\n            <path d=\"M460 130 L 540 90\"/>\n            <path d=\"M480 180 L 540 180\"/>\n          </g>\n          <g stroke=\"url(#pr-amber)\" stroke-width=\"1.8\" stroke-dasharray=\"5 4\" fill=\"none\" marker-end=\"url(#pr-arr-d)\">\n            <path d=\"M460 230 L 540 270\"/>\n          </g>\n\n          <!-- arrows: reviewers → sign-off (only when all approved) -->\n          <g stroke=\"rgba(122,240,184,0.55)\" stroke-width=\"1.6\" fill=\"none\" marker-end=\"url(#pr-arr)\">\n            <path d=\"M740 90  C 820 90, 870 140, 900 175\"/>\n            <path d=\"M740 180 L 900 185\"/>\n          </g>\n          <g stroke=\"rgba(245,197,107,0.55)\" stroke-width=\"1.6\" stroke-dasharray=\"5 4\" fill=\"none\">\n            <path d=\"M740 270 C 820 270, 870 230, 900 200\"/>\n          </g>\n\n          <!-- escalation timer indicator (dashed loop) -->\n          <g>\n            <rect x=\"540\" y=\"332\" width=\"200\" height=\"32\" rx=\"9\" fill=\"rgba(255,255,255,0.025)\" stroke=\"rgba(255,255,255,0.08)\" stroke-dasharray=\"3 3\"/>\n            <text x=\"640\" y=\"353\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.55)\" font-family=\"'JetBrains Mono'\" font-size=\"9.5\">escalates to General Counsel at +24h</text>\n          </g>\n\n          <!-- bottom legend -->\n          <g font-family=\"'JetBrains Mono'\" font-size=\"9\" fill=\"rgba(255,255,255,0.45)\">\n            <circle cx=\"50\" cy=\"345\" r=\"4\" fill=\"#7AF0B8\"/><text x=\"62\" y=\"349\">approved</text>\n            <circle cx=\"160\" cy=\"345\" r=\"4\" fill=\"#F5C56B\"/><text x=\"172\" y=\"349\">in review</text>\n            <circle cx=\"270\" cy=\"345\" r=\"4\" fill=\"#9EBAF6\"/><text x=\"282\" y=\"349\">requested</text>\n            <text x=\"380\" y=\"349\">·  rule applied: capex &gt; 250K → CFO + Legal in parallel</text>\n          </g>\n        </svg>\n      </div>\n\n      <div class=\"cv-ledger\">\n        <div class=\"hd\"><span>Audit ledger · this request</span><span class=\"right\">tamper-evident · hash-chain · live</span></div>\n        <div class=\"lg-row\">\n          <div class=\"av a\">HA</div>\n          <div class=\"body\"><b>Hessa A.</b> raised request #4892 · AED 280,000<div class=\"det\">capex · 32 SKUs · vendor: Tier-1 ITS · justification attached</div></div>\n          <span class=\"pill ok\">SUBMITTED</span>\n          <span class=\"ts\">09:14</span>\n        </div>\n        <div class=\"lg-row\">\n          <div class=\"av d\">SY</div>\n          <div class=\"body\"><b>System</b> · routed via Capex template · rule: amount &gt; 250K → CFO + Legal in parallel<div class=\"det\">policy version 3.2 · effective 01-Jan-2026 · hash 8f3a2c…</div></div>\n          <span class=\"pill ok\">ROUTED</span>\n          <span class=\"ts\">09:14</span>\n        </div>\n        <div class=\"lg-row\">\n          <div class=\"av a\">FA</div>\n          <div class=\"body\"><b>Faisal A. · Dept head</b> · approved with note <i>\"in line with FY26 plan\"</i><div class=\"det\">decision time 28 min · attached: capacity-plan-fy26.pdf</div></div>\n          <span class=\"pill ok\">APPROVED</span>\n          <span class=\"ts\">09:42</span>\n        </div>\n        <div class=\"lg-row\">\n          <div class=\"av b\">RM</div>\n          <div class=\"body\"><b>Reem M. · CFO</b> · approved · budget line confirmed<div class=\"det\">decision time 1h 32m · budget-line: ITS-2026-Q2 · remaining AED 740K</div></div>\n          <span class=\"pill ok\">APPROVED</span>\n          <span class=\"ts\">11:14</span>\n        </div>\n        <div class=\"lg-row\">\n          <div class=\"av c\">JM</div>\n          <div class=\"body\"><b>Jasem M. · Legal</b> · request received · vendor T&amp;Cs check started<div class=\"det\">SLA 24h · 18h remaining · auto-escalates to General Counsel at +24h</div></div>\n          <span class=\"pill warn\">IN REVIEW</span>\n          <span class=\"ts\">11:14</span>\n        </div>\n      </div>\n\n    </div>\n\n    <p style=\"text-align:center; color:var(--mist-60); font-size:.85rem; margin-top:1.5rem; font-family:'JetBrains Mono';\">A representative request. Names, request numbers and figures shown are illustrative — every deployment runs on the client's own approval matrix and policy library.</p>\n  </div>\n</section>\n\n<!-- ============== ANATOMY ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:3.5rem;\">\n      <span class=\"eyebrow\">Anatomy</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Six capabilities. Engineered around one outcome.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">An approval that lands faster, with fewer phone calls — and a record an auditor can replay clause-by-clause.</p>\n    </div>\n\n    <div class=\"module-stack reveal-stagger\">\n\n      <!-- 01 RULE ENGINE -->\n      <div class=\"module\">\n        <div class=\"module-text\">\n          <div class=\"num\">01 — Rule engine</div>\n          <h3>Configure your policy in plain language. The engine does the routing.</h3>\n          <p class=\"lead\">A declarative rules language for the procurement policy itself. Thresholds, vendor categories, project codes, classification, geography — combined into routing rules that procurement officers can edit themselves.</p>\n          <ul>\n            <li>Declarative policy DSL · readable by non-engineers</li>\n            <li>Versioned rules · diffable, reviewable, signed</li>\n            <li>Dry-run mode: simulate a new policy on the last 90 days</li>\n            <li>Hot reload · zero-downtime deploys</li>\n            <li>Per-business-unit policy · group-wide override</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>policy.capex.v3.2.dsl · last edit Reem M.</span></div>\n          <div class=\"mv-body\">\n<pre class=\"code-block\"><span class=\"c\">// Capex policy · v3.2 · effective 2026-01-01</span>\n\n<span class=\"k\">when</span> <span class=\"t\">request.type</span> == <span class=\"s\">\"capex\"</span> <span class=\"k\">and</span> <span class=\"t\">request.amount</span> &gt; <span class=\"n\">250_000</span> <span class=\"k\">then</span>\n  <span class=\"k\">require</span> [\n    <span class=\"t\">approver.dept_head</span>,                  <span class=\"c\">// serial</span>\n    <span class=\"k\">parallel</span> [\n      <span class=\"t\">approver.cfo</span>,\n      <span class=\"t\">approver.legal_counsel</span>           <span class=\"c\">// runs in parallel</span>\n    ]\n  ]\n  <span class=\"k\">sla</span> { dept_head: <span class=\"n\">8h</span>, cfo: <span class=\"n\">24h</span>, legal_counsel: <span class=\"n\">24h</span> }\n  <span class=\"k\">on_breach</span> <span class=\"k\">escalate_to</span> <span class=\"t\">approver.general_counsel</span>\n\n<span class=\"k\">when</span> <span class=\"t\">request.type</span> == <span class=\"s\">\"capex\"</span> <span class=\"k\">and</span> <span class=\"t\">request.amount</span> &gt; <span class=\"n\">50_000</span> <span class=\"k\">then</span>\n  <span class=\"k\">require</span> [ <span class=\"t\">approver.dept_head</span> ]\n  <span class=\"k\">sla</span> { dept_head: <span class=\"n\">24h</span> }\n\n<span class=\"c\">// recurring vendors with valid framework agreement skip dept-head</span>\n<span class=\"k\">when</span> <span class=\"t\">vendor.tier</span> == <span class=\"s\">\"recurring\"</span> <span class=\"k\">and</span> <span class=\"t\">vendor.framework</span> <span class=\"k\">is</span> <span class=\"t\">active</span> <span class=\"k\">then</span>\n  <span class=\"k\">skip</span> <span class=\"t\">approver.dept_head</span>\n  <span class=\"k\">audit_note</span> <span class=\"s\">\"framework-agreement bypass\"</span>\n</pre>\n          </div>\n        </div>\n      </div>\n\n      <!-- 02 ROUTING TEMPLATES -->\n      <div class=\"module flip\">\n        <div class=\"module-text\">\n          <div class=\"num\">02 — Routing templates</div>\n          <h3>Three templates cover 92% of requests. The other 8% get a human.</h3>\n          <p class=\"lead\">Out-of-the-box routing for Capex, Opex and Recurring-vendor purchases — each tunable to your organisation's structure. Edge cases route to a procurement officer who can configure or override, with the audit log making the override visible.</p>\n          <ul>\n            <li>Capex template: serial dept-head → parallel CFO + Legal</li>\n            <li>Opex template: dept-head only (under threshold) or finance manager</li>\n            <li>Recurring-vendor: framework-agreement bypass with audit note</li>\n            <li>Custom templates: scope, geography, classification, project code</li>\n            <li>Override workflow with required justification &amp; sign-off</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Templates · last 30 days · live</span></div>\n          <div class=\"mv-body\">\n            <div class=\"tpl-grid\">\n              <div class=\"tpl-card\">\n                <div class=\"hd\"><b>Capex</b><span class=\"ct\">312 reqs · 22%</span></div>\n                <div class=\"desc\">Capital expenditure · IT hardware, fit-out, equipment. Threshold-aware routing with parallel CFO/Legal at 250K.</div>\n                <div class=\"lane\">\n                  <span>Initiator</span>\n                  <span>Dept-head</span>\n                  <span class=\"par\">CFO ∥ Legal</span>\n                  <span class=\"fin\">Sign-off</span>\n                </div>\n              </div>\n              <div class=\"tpl-card\">\n                <div class=\"hd\"><b>Opex</b><span class=\"ct\">762 reqs · 54%</span></div>\n                <div class=\"desc\">Operating expenditure · supplies, maintenance, services. Lighter routing — dept-head only under 50K.</div>\n                <div class=\"lane\">\n                  <span>Initiator</span>\n                  <span>Dept-head</span>\n                  <span class=\"fin\">Sign-off</span>\n                </div>\n              </div>\n              <div class=\"tpl-card\">\n                <div class=\"hd\"><b>Framework</b><span class=\"ct\">218 reqs · 16%</span></div>\n                <div class=\"desc\">Recurring vendor with active framework agreement. Skips dept-head; audit-note records the bypass.</div>\n                <div class=\"lane\">\n                  <span>Initiator</span>\n                  <span class=\"fin\">Sign-off</span>\n                </div>\n              </div>\n            </div>\n            <div style=\"margin-top:1rem; padding:.85rem; border:1px dashed rgba(255,255,255,0.08); border-radius:8px; font-size:.78rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">\n              108 requests · 8% · routed to procurement officer for manual override → all logged, justified, signed.\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 03 SLA / TIMERS -->\n      <div class=\"module\">\n        <div class=\"module-text\">\n          <div class=\"num\">03 — SLAs &amp; escalation timers</div>\n          <h3>Reviewers don't sit on requests — the engine doesn't let them.</h3>\n          <p class=\"lead\">Per-stage SLAs with escalation timers. If a reviewer is on leave or hasn't actioned the request inside their window, the engine auto-escalates to the named delegate or to a senior reviewer.</p>\n          <ul>\n            <li>Per-stage SLA configurable in the policy DSL</li>\n            <li>Auto-escalate to named delegate when reviewer is on leave</li>\n            <li>Escalate to senior reviewer when SLA breached</li>\n            <li>WhatsApp / Teams / email reminder cadence</li>\n            <li>Out-of-office calendar integration · proactive routing</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>SLA performance · last 30 days</span></div>\n          <div class=\"mv-body\">\n            <div class=\"eval-grid\">\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Median time-to-first-review</b><span class=\"pct\">4.2h</span></div>\n                <div class=\"bar\"><i style=\"width:35%\"></i></div>\n                <div class=\"meta\">Was 38h before deployment</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Median request cycle</b><span class=\"pct\">11.8h</span></div>\n                <div class=\"bar\"><i style=\"width:42%\"></i></div>\n                <div class=\"meta\">−71% vs paper baseline</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>SLA breached</b><span class=\"pct\" style=\"color:#F5C56B;\">2.1%</span></div>\n                <div class=\"bar\"><i style=\"width:21%\"></i></div>\n                <div class=\"meta\">Auto-escalated · 38 in 30d</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Auto-routed to delegate</b><span class=\"pct\">141</span></div>\n                <div class=\"bar\"><i style=\"width:65%\"></i></div>\n                <div class=\"meta\">When reviewer was OOO</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Re-routed manually</b><span class=\"pct\">28</span></div>\n                <div class=\"bar\"><i style=\"width:14%\"></i></div>\n                <div class=\"meta\">By procurement officer · all logged</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Cycle for capex &gt; 250K</b><span class=\"pct\">22.8h</span></div>\n                <div class=\"bar\"><i style=\"width:48%\"></i></div>\n                <div class=\"meta\">Even with parallel CFO + Legal</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 04 AUDIT LEDGER -->\n      <div class=\"module flip\">\n        <div class=\"module-text\">\n          <div class=\"num\">04 — Tamper-evident audit ledger</div>\n          <h3>An auditor can replay any request. Forensically.</h3>\n          <p class=\"lead\">Every state change is appended to a hash-chained ledger. The full request — including the policy version that was active when it was raised — can be replayed years later. Auditor evidence packs export in one click.</p>\n          <ul>\n            <li>Append-only ledger · hash-chain across entries</li>\n            <li>Policy version pinned per request · forensic replay</li>\n            <li>Signed PDF evidence pack · regulator-ready</li>\n            <li>Configurable retention · 7 years default</li>\n            <li>Dual-key verification on dispute · external auditor friendly</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Ledger entries · request #4892</span></div>\n          <div class=\"mv-body\">\n            <div class=\"lg-row\">\n              <div class=\"av a\">HA</div>\n              <div class=\"body\"><b>Hessa A.</b> raised request<div class=\"det\">hash 8f3a2c…b918 · prev a219cd…</div></div>\n              <span class=\"pill ok\">v3.2</span>\n              <span class=\"ts\">09:14:02</span>\n            </div>\n            <div class=\"lg-row\">\n              <div class=\"av d\">SY</div>\n              <div class=\"body\"><b>System</b> applied Capex template<div class=\"det\">hash c41f9a…d228 · rule: capex.threshold.parallel</div></div>\n              <span class=\"pill ok\">RULE</span>\n              <span class=\"ts\">09:14:03</span>\n            </div>\n            <div class=\"lg-row\">\n              <div class=\"av a\">FA</div>\n              <div class=\"body\"><b>Faisal A.</b> approved · serial step 1 of 2<div class=\"det\">hash 3e88aa…ff14 · attached: capacity-plan-fy26.pdf · sha256 verified</div></div>\n              <span class=\"pill ok\">SIGN</span>\n              <span class=\"ts\">09:42:11</span>\n            </div>\n            <div class=\"lg-row\">\n              <div class=\"av b\">RM</div>\n              <div class=\"body\"><b>Reem M.</b> approved · parallel step 2a of 2<div class=\"det\">hash 7c1aaf…2901 · budget line: ITS-2026-Q2</div></div>\n              <span class=\"pill ok\">SIGN</span>\n              <span class=\"ts\">11:14:38</span>\n            </div>\n            <div class=\"lg-row\">\n              <div class=\"av d\">SY</div>\n              <div class=\"body\"><b>System</b> chain integrity verified · 5 entries · OK<div class=\"det\">last verified 12:08:14 · scheduled re-verify in 6h</div></div>\n              <span class=\"pill ok\">CHAIN OK</span>\n              <span class=\"ts\">12:08</span>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 05 REVIEWER EXPERIENCE -->\n      <div class=\"module\">\n        <div class=\"module-text\">\n          <div class=\"num\">05 — Reviewer experience</div>\n          <h3>Approve from your phone in two taps. With evidence.</h3>\n          <p class=\"lead\">Reviewers don't open the laptop unless they have to. Push notifications, a one-screen request summary with the relevant clauses pre-quoted, and tap-to-approve / tap-to-question. With audit hash applied automatically.</p>\n          <ul>\n            <li>Mobile push notifications · iOS · Android</li>\n            <li>One-screen summary: amount, vendor, justification, policy clause</li>\n            <li>Tap to approve · tap to question · tap to delegate</li>\n            <li>Comments are part of the audit trail · attachable evidence</li>\n            <li>Out-of-office handover · with named delegate &amp; coverage window</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Reviewer · mobile · request preview</span></div>\n          <div class=\"mv-body\">\n            <div class=\"mob-shell\">\n              <div class=\"top\">\n                <div>\n                  <b>Approval needed</b>\n                  <div style=\"font-size:.7rem;color:rgba(255,255,255,0.5);font-family:'JetBrains Mono';margin-top:.15rem;\">PR-4892 · IT Hardware refresh</div>\n                </div>\n                <span class=\"pill\">SLA 18h</span>\n              </div>\n              <div class=\"mob-row\"><span class=\"lbl\">Amount</span><span class=\"v\">AED 280,000</span></div>\n              <div class=\"mob-row\"><span class=\"lbl\">Initiator</span><span class=\"v\">Hessa A. · IT &amp; Ops</span></div>\n              <div class=\"mob-row\"><span class=\"lbl\">Vendor</span><span class=\"v\">Tier-1 ITS · framework</span></div>\n              <div class=\"mob-row\"><span class=\"lbl\">Budget line</span><span class=\"v\">ITS-2026-Q2</span></div>\n              <div class=\"mob-row\"><span class=\"lbl\">Stage</span><span class=\"v\">2 of 3 · CFO sign</span></div>\n              <div class=\"mob-aux\">\n                <span>view 32 SKUs</span>\n                <span>view justification</span>\n                <span>view policy v3.2</span>\n              </div>\n              <div class=\"mob-actions\">\n                <div class=\"b ok\">Approve</div>\n                <div class=\"b no\">Question</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 06 INTEGRATIONS -->\n      <div class=\"module flip\">\n        <div class=\"module-text\">\n          <div class=\"num\">06 — Integrations</div>\n          <h3>Plays nicely with the ERP, the e-signature, the directory you already run.</h3>\n          <p class=\"lead\">SAP, Oracle, Microsoft Dynamics, Workday — the engine reads your master data and writes back the signed PO. SSO via your existing IdP. No double entry, no parallel master data.</p>\n          <ul>\n            <li>SAP, Oracle, Microsoft Dynamics, Workday · vendor &amp; budget master</li>\n            <li>DocuSign · Adobe Sign · qualified e-signature on output PDFs</li>\n            <li>Azure AD · Okta · Active Directory for SSO and reviewer roster</li>\n            <li>Exchange / Google Calendar for OOO awareness</li>\n            <li>WhatsApp Business · Teams · Slack for in-line approvals</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Connected systems · this client</span></div>\n          <div class=\"mv-body\">\n            <div class=\"thr-row\">\n              <div class=\"body\"><b>SAP S/4HANA · vendor master</b><div class=\"det\">14,820 vendors · sync every 4h · last 11:42</div></div>\n              <div class=\"v\">live</div>\n              <div class=\"actions\"><span>⟳</span><span>⚙</span></div>\n            </div>\n            <div class=\"thr-row\">\n              <div class=\"body\"><b>SAP S/4HANA · budget &amp; cost-centres</b><div class=\"det\">2,108 cost-centres · 38 cost-objects · sync hourly</div></div>\n              <div class=\"v\">live</div>\n              <div class=\"actions\"><span>⟳</span><span>⚙</span></div>\n            </div>\n            <div class=\"thr-row\">\n              <div class=\"body\"><b>Azure AD · reviewer roster</b><div class=\"det\">182 reviewers · OOO calendar enabled · MFA enforced</div></div>\n              <div class=\"v\">live</div>\n              <div class=\"actions\"><span>⟳</span><span>⚙</span></div>\n            </div>\n            <div class=\"thr-row\">\n              <div class=\"body\"><b>DocuSign · evidence pack signing</b><div class=\"det\">Qualified signature · UAE legal-form ready</div></div>\n              <div class=\"v\">live</div>\n              <div class=\"actions\"><span>⟳</span><span>⚙</span></div>\n            </div>\n            <div class=\"thr-row\">\n              <div class=\"body\"><b>Microsoft Teams · in-line approval card</b><div class=\"det\">Reviewer can approve in DM without leaving Teams</div></div>\n              <div class=\"v\">live</div>\n              <div class=\"actions\"><span>⟳</span><span>⚙</span></div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============== INTEGRATIONS GRID ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2rem;\">\n      <span class=\"eyebrow\">Stack</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">A workflow engine that fits.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Modular, container-shipped, and integration-friendly with the systems your CFO already paid for.</p>\n    </div>\n\n    <div class=\"integ-grid reveal-stagger\">\n      <div class=\"integ\"><div class=\"lo\">SAP</div><div class=\"ty\">ERP</div></div>\n      <div class=\"integ\"><div class=\"lo\">Oracle</div><div class=\"ty\">ERP</div></div>\n      <div class=\"integ\"><div class=\"lo\">MS Dynamics</div><div class=\"ty\">ERP</div></div>\n      <div class=\"integ\"><div class=\"lo\">Workday</div><div class=\"ty\">HR · Cost</div></div>\n      <div class=\"integ\"><div class=\"lo\">DocuSign</div><div class=\"ty\">e-Sign</div></div>\n      <div class=\"integ\"><div class=\"lo\">Adobe Sign</div><div class=\"ty\">e-Sign</div></div>\n      <div class=\"integ\"><div class=\"lo\">Azure AD</div><div class=\"ty\">SSO · MFA</div></div>\n      <div class=\"integ\"><div class=\"lo\">Okta</div><div class=\"ty\">SSO</div></div>\n      <div class=\"integ\"><div class=\"lo\">Teams · Slack</div><div class=\"ty\">Approvals</div></div>\n      <div class=\"integ\"><div class=\"lo\">WhatsApp</div><div class=\"ty\">Approvals</div></div>\n      <div class=\"integ\"><div class=\"lo\">Postgres</div><div class=\"ty\">Data</div></div>\n      <div class=\"integ\"><div class=\"lo\">REST · Webhook</div><div class=\"ty\">Anything</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== STORIES ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2.5rem;\">\n      <span class=\"eyebrow\">In production</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Three procurement teams. Same engine, configured differently.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Anonymized at the client's request. Industry, scale and outcomes are real and verifiable on request under NDA.</p>\n    </div>\n\n    <div class=\"stories reveal-stagger\">\n\n      <article class=\"story\">\n        <div class=\"story-head\">\n          <span class=\"seg-tag\">Conglomerate · 1,400 reqs/mo</span>\n          <h3>Capex requests cleared in a day, not a week.</h3>\n          <span class=\"where\">Diversified holding · 14 BUs · 1,400 monthly requests</span>\n        </div>\n        <div class=\"story-body\">\n          <p>The procurement team used to run a 9-step, mostly-email approval process where requests went stale waiting for a reviewer who was on leave. Now requests route around OOO automatically and the median capex cycle is under 24 hours.</p>\n          <p class=\"quote\">\"We saved 380 reviewer-hours in the first month — and zero of those reviews were skipped.\"</p>\n          <p class=\"quote-by\">— group head of procurement</p>\n          <div class=\"story-kpis\">\n            <div class=\"story-kpi\"><div class=\"v\">−71%</div><div class=\"l\">cycle time</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">100%</div><div class=\"l\">audit coverage</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">14 BUs</div><div class=\"l\">on one engine</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">1,400</div><div class=\"l\">requests/month</div></div>\n          </div>\n        </div>\n      </article>\n\n      <article class=\"story\">\n        <div class=\"story-head\">\n          <span class=\"seg-tag\">Government-related · capex</span>\n          <h3>An audit-grade trail that satisfies the regulator the first time.</h3>\n          <span class=\"where\">Public-sector entity · capex committee · regulator-facing</span>\n        </div>\n        <div class=\"story-body\">\n          <p>Audit prep used to be a six-week scramble — collating emails, PDFs, Excel signatures and meeting minutes. The first regulator visit after deployment was the first one to finish in a single afternoon.</p>\n          <p class=\"quote\">\"The auditors said it's the cleanest evidence pack they've seen all year. We didn't have to defend a single decision.\"</p>\n          <p class=\"quote-by\">— compliance director</p>\n          <div class=\"story-kpis\">\n            <div class=\"story-kpi\"><div class=\"v\">100%</div><div class=\"l\">audit coverage</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">1 day</div><div class=\"l\">audit prep · was 6 weeks</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">7 yr</div><div class=\"l\">tamper-evident retention</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">0</div><div class=\"l\">decisions challenged</div></div>\n          </div>\n        </div>\n      </article>\n\n      <article class=\"story\">\n        <div class=\"story-head\">\n          <span class=\"seg-tag\">Financial-services · vendor onboarding</span>\n          <h3>Vendor onboarding turned into a self-service flow with a real reviewer at the gate.</h3>\n          <span class=\"where\">Banking-adjacent FS · 220 active vendors</span>\n        </div>\n        <div class=\"story-body\">\n          <p>Vendor onboarding used to take 4–6 weeks of email back-and-forth between procurement, legal, risk and IT. The same flow now runs through the engine: vendor uploads docs, reviewers act on a single screen, and the vendor master in SAP gets the green flag automatically.</p>\n          <p class=\"quote\">\"Vendors comment on it. They go from 'painful old bank' to 'shockingly modern' in their first interaction with us.\"</p>\n          <p class=\"quote-by\">— head of vendor management</p>\n          <div class=\"story-kpis\">\n            <div class=\"story-kpi\"><div class=\"v\">−68%</div><div class=\"l\">vendor onboarding time</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">100%</div><div class=\"l\">KYC docs verified</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">220</div><div class=\"l\">vendors live</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">SAP</div><div class=\"l\">vendor master in sync</div></div>\n          </div>\n        </div>\n      </article>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============== TIMELINE ============== -->\n<section class=\"section\">\n  <div class=\"container split reveal-stagger\" style=\"align-items:flex-start;gap:3rem;\">\n    <div>\n      <span class=\"eyebrow\">Implementation</span>\n      <h2 style=\"margin-top:1rem;max-width:18ch;\">Live in 10 weeks. Carefully.</h2>\n      <p style=\"margin-top:1.25rem;color:var(--mist-80);\">Procurement is high-trust. We move slowly on policy and quickly on plumbing — because the engine is only useful if your reviewers actually open it.</p>\n      <a href=\"/contact\" class=\"btn btn-primary\" style=\"margin-top:1.5rem;\">Talk through your rollout\n        <svg class=\"arrow\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n      </a>\n    </div>\n\n    <div class=\"timeline\">\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 1–2 · Discovery</div>\n        <h4>Map your policy &amp; your matrix</h4>\n        <p>Review existing procurement policy, approval matrix, current cycle times, regulator/audit requirements. Define gold metrics and a backlog of test cases (real recent requests).</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 3–4 · Provision</div>\n        <h4>Stand up the environment</h4>\n        <p>VPC or on-prem cluster. SSO with your IdP. ERP connectors. Calendar &amp; OOO awareness. Reviewer roster imported. Audit ledger configured.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 5 · Codify policy</div>\n        <h4>Translate the policy into the DSL</h4>\n        <p>Write Capex, Opex, Recurring-vendor templates against your real policy. Dry-run them on the last 90 days of requests. Tune until expected outcomes match.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 6 · Internal beta</div>\n        <h4>Procurement officers run shadow flows</h4>\n        <p>Procurement officers raise duplicate requests in the new engine alongside the old process. Compare outcomes. Identify edge cases. Adjust rules.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 7–8 · Reviewer training</div>\n        <h4>Train reviewers · enable mobile</h4>\n        <p>One-hour session per reviewer cohort. Mobile push wired up. OOO delegate registration. The engine starts sending real requests for one BU.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 9–10 · BU-by-BU rollout</div>\n        <h4>One BU at a time</h4>\n        <p>Each BU goes live on a Monday morning, with daily check-ins for the first week and weekly for the next month. Old process retired only after the new one has handled a full month of that BU's traffic.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== COMPLIANCE ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2rem;\">\n      <span class=\"eyebrow\">Compliance</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Built for audited environments.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">We design to the strictest framework in the room. SOC 2, ISO 27001, UAE NESA, and sector-specific frameworks on request.</p>\n    </div>\n\n    <div class=\"compl-grid reveal-stagger\">\n      <div class=\"compl\"><div class=\"lo\">SOC 2 · Type II</div><div class=\"ty\">Security</div></div>\n      <div class=\"compl\"><div class=\"lo\">ISO 27001</div><div class=\"ty\">Infosec</div></div>\n      <div class=\"compl\"><div class=\"lo\">ISO 9001</div><div class=\"ty\">Quality</div></div>\n      <div class=\"compl\"><div class=\"lo\">UAE NESA</div><div class=\"ty\">Sovereign</div></div>\n      <div class=\"compl\"><div class=\"lo\">UAE PDPL</div><div class=\"ty\">Privacy</div></div>\n      <div class=\"compl\"><div class=\"lo\">GDPR-equiv</div><div class=\"ty\">Privacy</div></div>\n      <div class=\"compl\"><div class=\"lo\">SOX-ready</div><div class=\"ty\">Controls</div></div>\n      <div class=\"compl\"><div class=\"lo\">PCI-DSS</div><div class=\"ty\">Payments</div></div>\n      <div class=\"compl\"><div class=\"lo\">AES-256</div><div class=\"ty\">Encryption</div></div>\n      <div class=\"compl\"><div class=\"lo\">Hash-chain</div><div class=\"ty\">Audit</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== FAQ ============== -->\n<section class=\"section\">\n  <div class=\"container split reveal-stagger\" style=\"align-items:flex-start; gap:3rem;\">\n    <div>\n      <span class=\"eyebrow\">Common questions</span>\n      <h2 style=\"margin-top:1rem;max-width:18ch;\">The things every procurement and finance head asks.</h2>\n      <p style=\"margin-top:1.25rem;color:var(--mist-80);\">If yours isn't here, ask us — we welcome the questionnaire and the audit conversation.</p>\n      <a href=\"/contact\" class=\"btn btn-outline\" style=\"margin-top:1.25rem;\">Send your questionnaire</a>\n    </div>\n\n    <div class=\"faq\">\n      <details>\n        <summary>Can we configure the rules ourselves?</summary>\n        <p>Yes. The policy DSL is designed to be readable and writeable by procurement officers, not engineers. Rule changes are versioned, diffable, dry-runnable against the last 90 days of requests, and require sign-off before they go live. We train your team to own the rules — we're not a managed service for your policy.</p>\n      </details>\n      <details>\n        <summary>How does it handle parallel reviewers and partial approvals?</summary>\n        <p>Both serial and parallel reviewer chains are supported. A single rule can specify \"dept-head, then [CFO and Legal in parallel], then sign-off\". Partial approvals (one reviewer says yes, another flags a question) hold the request in a clear \"pending question\" state with the audit trail intact. Nothing advances until the question is resolved.</p>\n      </details>\n      <details>\n        <summary>What happens if a reviewer is on leave?</summary>\n        <p>The engine reads your Exchange / Google Calendar OOO and reroutes proactively to the named delegate before the request even lands. If a reviewer becomes unreachable mid-flight (sudden leave, illness), the SLA timer escalates to a senior reviewer or named delegate. All re-routings are logged with the reason.</p>\n      </details>\n      <details>\n        <summary>Does it integrate with our ERP?</summary>\n        <p>Yes — SAP, Oracle, Microsoft Dynamics and Workday are all live in production deployments. The engine reads your vendor master, budget lines and cost centres, and writes back signed POs. We use your existing master data; we don't ask you to maintain two copies.</p>\n      </details>\n      <details>\n        <summary>Is the audit log tamper-evident?</summary>\n        <p>Yes. Every entry is hash-chained to the previous entry. Tampering with any entry breaks the chain and is detectable instantly. Chain integrity is verified continuously. For disputes, dual-key verification is supported with an external auditor's key — they can prove independently that the ledger has not been altered.</p>\n      </details>\n      <details>\n        <summary>Can reviewers approve from their phone?</summary>\n        <p>Yes. iOS &amp; Android push notifications, with a one-screen request summary and tap-to-approve. The mobile view is the audit-equivalent of the desktop — same hash, same trail. We have CFOs running their entire approval queue from the phone.</p>\n      </details>\n      <details>\n        <summary>How long does it take to deploy on our process?</summary>\n        <p>Standard rollout is 10 weeks for a multi-BU enterprise. The biggest variable is policy translation — codifying your existing approval matrix into the DSL. Faster is possible if your policy is already clean and documented; slower if discovery uncovers undocumented exceptions (it usually does).</p>\n      </details>\n      <details>\n        <summary>What's pricing?</summary>\n        <p>A platform subscription scaled by monthly request volume and number of integrated systems, plus a one-time implementation fee. Sovereign / on-prem deployments are quoted separately. We share a worked example in the discovery call — no obligation.</p>\n      </details>\n    </div>\n  </div>\n</section>\n\n<!-- ============== CROSS-LINK RIBBON ============== -->\n<section class=\"section\" style=\"padding-top:0;\">\n  <div class=\"container reveal\">\n    <div class=\"ribbon\">\n      Want full ops visibility too? — <a href=\"/solutions/business-tracking\">read the Business Tracking deep-dive →</a>\n    </div>\n  </div>\n</section>\n\n<!-- ============== CTA ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"cta-banner reveal\">\n      <div class=\"cta-glow\" aria-hidden=\"true\"></div>\n      <span class=\"eyebrow\" style=\"justify-content:center;\">Book a workflow walkthrough</span>\n      <h2 style=\"margin-top:1rem;\">See it on your approval matrix.</h2>\n      <p>45 minutes. Bring your policy and your three most painful approval flows. We'll show you how the engine would have routed them.</p>\n      <div style=\"display:flex; gap:.85rem; justify-content:center; flex-wrap:wrap; margin-top:1.5rem;\">\n        <a href=\"/contact\" class=\"btn btn-primary btn-lg\">Book a workflow walkthrough\n          <svg class=\"arrow\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n        </a>\n        <a href=\"/contact\" class=\"btn btn-outline btn-lg\">Send security questionnaire</a>\n      </div>\n    </div>\n  </div>\n</section>";

export default function SolutionProcurementApprovalEnginePage() {
  return (
    <>
      <JsonLd data={jsonLd} />
      <div dangerouslySetInnerHTML={{ __html: body }} />
    </>
  );
}
